if command == "add":
    if len(sys.argv) < 3:
        print("Usage: python todo.py add \"任务内容\"")
        return
    todos = load_todos()
    todos.append(sys.argv[2])
    save_todos(todos)

elif command == "list":
    todos = load_todos()
    for i, todo in enumerate(todos, start=1):
        print(f"{i}: {todo}")

elif command == "remove":
    if len(sys.argv) < 3:
        print("Usage: python todo.py remove <ID>")
        return
    todos = load_todos()
    idx = int(sys.argv[2]) - 1
    if 0 <= idx < len(todos):
        todos.pop(idx)
        save_todos(todos)

else:
    print(f"Unknown command: {command}")

